<content>
export enum Severity {
  CRITICAL = 'critical',
  HIGH = 'high',
  MEDIUM = 'medium',
  LOW = 'low',
  INFO = 'info'
}

export enum FindingCategory {
  CODE_QUALITY = 'code_quality',
  STRUCTURE = 'structure',
  SECURITY = 'security',
  PERFORMANCE = 'performance',
  DOCUMENTATION = 'documentation',
  TESTING = 'testing',
  DEPENDENCIES = 'dependencies',
  BEST_PRACTICES = 'best_practices'
}

export enum FixStrategy {
  AUTOMATED = 'automated',
  AI_ASSISTED = 'ai_assisted',
  INTERACTIVE = 'interactive',
  MANUAL = 'manual'
}

export interface FileMetadata {
  path: string;
  relativePath: string;
  size: number;
  extension: string;
  language?: string;
  lines: number;
  lastModified: Date;
}

export interface ProjectManifest {
  rootPath: string;
  projectType: string;
  files: FileMetadata[];
  totalFiles: number;
  totalLines: number;
  languages: Record<string, number>;
  hasGit: boolean;
  hasTests: boolean;
  packageManager?: 'npm' | 'yarn' | 'pnpm';
  dependencies?: Record<string, string>;
  devDependencies?: Record<string, string>;
}

export interface Finding {
  id: string;
  category: FindingCategory;
  severity: Severity;
  title: string;
  description: string;
  file?: string;
  line?: number;
  column?: number;
  code?: string;
  suggestion?: string;
  fixStrategy: FixStrategy;
  autoFixable: boolean;
  metadata?: Record<string, any>;
}

export interface AuditReport {
  timestamp: Date;
  projectPath: string;
  manifest: ProjectManifest;
  findings: Finding[];
  summary: {
    totalFindings: number;
    bySeverity: Record<Severity, number>;
    byCategory: Record<FindingCategory, number>;
    autoFixableCount: number;
  };
  score: number; // 0-100
  recommendations: string[];
}

export interface RepairResult {
  success: boolean;
  findingId: string;
  strategy: FixStrategy;
  changes: FileChange[];
  error?: string;
  aiReasoning?: string;
}

export interface FileChange {
  file: string;
  type: 'create' | 'modify' | 'delete';
  originalContent?: string;
  newContent?: string;
  diff?: string;
}

export interface BCBConfig {
  rules: {
    [key: string]: {
      enabled: boolean;
      severity?: Severity;
      options?: Record<string, any>;
    };
  };
  ignore: string[];
  ai: {
    provider: 'openai' | 'anthropic';
    model?: string;
    apiKey?: string;
    maxTokens?: number;
  };
  autoFix: {
    enabled: boolean;
    requireApproval: boolean;
    strategies: FixStrategy[];
  };
  output: {
    format: 'json' | 'html' | 'markdown' | 'terminal';
    path?: string;
    verbose: boolean;
  };
}

export interface AnalysisContext {
  manifest: ProjectManifest;
  config: BCBConfig;
  file?: FileMetadata;
  ast?: any;
  content?: string;
}

export interface Plugin {
  name: string;
  version: string;
  description: string;
  analyze(context: AnalysisContext): Promise<Finding[]>;
  repair?(finding: Finding, context: AnalysisContext): Promise<RepairResult>;
}

export interface AIProvider {
  name: string;
  analyzeCode(prompt: string, code: string, context: any): Promise<string>;
  suggestFix(finding: Finding, code: string): Promise<string>;
  generateCode(description: string, context: any): Promise<string>;
}
</content>
